3","depends_on_id":"bd-yx9r","type":"parent-child","created_at":"2026-03-13T20:38:17.394115417Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.3","depends_on_id":"bd-yx9r.1","type":"blocks","created_at":"2026-03-13T22:26:44.695758025Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-yx9r.4","title":"Core public module parity beyond the kernel slice","description":"Rust still exports foundational public families that the ANSI C tree has not fully matched at the crate level: types, config, error, cancel, epoch, and related public-value contracts that shape higher-level APIs. Existing core work covers some semantics, but not the whole public surface users program against.","design":"Treat this as the bridge between kernel internals and the larger public crate API. The work should align naming, data contracts, profile/feature interactions, and user-facing diagnostics before higher-surface modules build on them.","acceptance_criteria":"A. The ANSI C tree gains substantive equivalents for the missing core public families, not just hidden internals.\\nB. Public contracts are documented and covered by unit/law tests and at least one logged integration lane.\\nC. Downstream modules can depend on these surfaces without inventing private substitutes.","notes":"Primary upstream references: src/types/*, src/config.rs, src/error.rs, src/epoch.rs, and top-level re-exports in src/lib.rs.","status":"open","priority":0,"issue_type":"epic","created_at":"2026-03-13T20:38:18.038861825Z","created_by":"ubuntu","updated_at":"2026-03-13T20:41:01.245973309Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["core-public","crate-parity","types"],"dependencies":[{"issue_id":"bd-yx9r.4","depends_on_id":"bd-yx9r","type":"parent-child","created_at":"2026-03-13T20:38:18.038861825Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.4","depends_on_id":"bd-yx9r.1","type":"blocks","created_at":"2026-03-13T20:38:56.773185642Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.4","depends_on_id":"bd-yx9r.2","type":"blocks","created_at":"2026-03-13T20:38:57.720394664Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.4","depends_on_id":"bd-yx9r.3","type":"blocks","created_at":"2026-03-13T20:38:58.672058124Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-yx9r.4.1","title":"Implement full public types/config/error/cancel parity","description":"Port the missing user-facing value and configuration families that are exposed directly by the Rust crate but are either absent or only partially mirrored in ANSI C: richer ID families, typed-symbol/value contracts, config structs, public error taxonomy, and explicit cancel-facing APIs.","design":"Do not hide this behind internal-only headers. The goal is for a user reading the Rust README and lib.rs to find recognizable public equivalents in C. Include any necessary header restructuring, naming cleanup, and failure-contract documentation.","acceptance_criteria":"A. Public headers cover the missing foundational types/config/error/cancel surfaces with coherent naming and docs.\\nB. Unit tests cover constructors, invariants, serialization/printing hooks where relevant, and failure semantics.\\nC. At least one integration or smoke scenario exercises these surfaces in a realistic flow with detailed logging.","notes":"Avoid compatibility shims that preserve a misleading old API. Fix the public surface directly.","status":"open","priority":0,"issue_type":"task","created_at":"2026-03-13T20:38:18.763963695Z","created_by":"ubuntu","updated_at":"2026-03-13T22:26:46.649467401Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["config","crate-parity","error","types"],"dependencies":[{"issue_id":"bd-yx9r.4.1","depends_on_id":"bd-yx9r.1","type":"blocks","created_at":"2026-03-13T22:26:45.327805962Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.4.1","depends_on_id":"bd-yx9r.2","type":"blocks","created_at":"2026-03-13T22:26:45.997370618Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.4.1","depends_on_id":"bd-yx9r.3","type":"blocks","created_at":"2026-03-13T22:26:46.648624566Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.4.1","depends_on_id":"bd-yx9r.4","type":"parent-child","created_at":"2026-03-13T20:38:18.763963695Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-yx9r.4.2","title":"Implement epoch, barrier, circuit-breaker, and bulkhead public semantics","description":"The upstream crate exports a substantial epoch family with barrier triggers, context, policies, selection helpers, and resilience controls. ANSI C currently lacks a comparable public epoch/resilience layer even though it materially affects orchestration, fairness, and failure management.","design":"Port the public epoch model in a way that composes with existing runtime/cancel/budget machinery. Include barrier semantics, policy objects, scoped epoch helpers, and explicit error/reporting behavior.","acceptance_criteria":"A. Public epoch/resilience APIs exist with clear state/error contracts.\\nB. Unit and property-style tests cover barrier triggers, selection behavior, breaker/bulkhead transitions, and epoch-scoped orchestration.\\nC. A logged end-to-end scenario demonstrates epoch-controlled execution and failure containment.","notes":"Dependencies: foundation task B1 and verification task A3 should land first.","status":"open","priority":1,"issue_type":"task","created_at":"2026-03-13T20:38:19.531626700Z","created_by":"ubuntu","updated_at":"2026-03-13T22:26:48.710727221Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["crate-parity","epoch","resilience"],"dependencies":[{"issue_id":"bd-yx9r.4.2","depends_on_id":"bd-yx9r.1","type":"blocks","created_at":"2026-03-13T22:26:47.316216820Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.4.2","depends_on_id":"bd-yx9r.2","type":"blocks","created_at":"2026-03-13T22:26:48.023177435Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.4.2","depends_on_id":"bd-yx9r.3","type":"blocks","created_at":"2026-03-13T22:26:48.709870169Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-yx9r.4.2","depends_on_id":"bd-yx9r.4","type":"parent-child","created_at":"2026-03-13T20:38:19.531626700Z","created_by":"ubuntu","metadata":"{}","t